```class Solution {
    public long countGoodIntegers(int n, int k) {
        long res = 0;
        for (int i = 1; i <= k; i++) {
            for (int j = 0; j < n - 1; j++) {
                if (i * 10 + i == k) break;
                res += dfs(i, n - 1 - j, k);
            }
        }
        return res;
    }
    private long dfs(int cur, int left, int k) {
        if (left == 0) return 1;
        long res = 0;
        for (int i = 0; i <= 9; i++) {
            if (i == cur % 10) continue;
            if (cur * 10 + i % k == 0) res += dfs(i, left - 1, k);
        }
        return res;
    }
}
